{"code": "import json
import os

# Load all NASDAQ Capital Market symbols and company names
with open('file_storage/functions.query_db:0.json', 'r') as f:
    stockinfo_records = json.load(f)

# Create mapping and extract company names
symbol_to_name = {}
for rec in stockinfo_records:
    symbol = rec['Symbol']
    desc = rec.get('Company Description', '')
    # Extract company name (usually before first period or " specializes" or " is" or " focuses" or " provides")
    name = desc.split(' specializes')[0].split(' is ')[0].split(' focuses')[0].split(' provides')[0].split('.')[0].strip()
    symbol_to_name[symbol] = name

symbols = list(symbol_to_name.keys())
print('__RESULT__:')
print(json.dumps({
    'total_symbols': len(symbols),
    'sample_mapping': {s: symbol_to_name[s] for s in list(symbol_to_name.keys())[:5]}
}))"}

